Функция ОборотДебетПоКонтрагенту(Счет, Контрагент)

	Оборот = 0;

	Запрос = Новый Запрос;
	Запрос.Текст = 
		"ВЫБРАТЬ
		|	СУММА(ХозрасчетныйДвиженияССубконто.Сумма) КАК Сумма
		|ИЗ
		|	РегистрБухгалтерии.Хозрасчетный.ДвиженияССубконто КАК ХозрасчетныйДвиженияССубконто
		|ГДЕ
		|	ХозрасчетныйДвиженияССубконто.СчетДт = &Счет
		|	И (ХозрасчетныйДвиженияССубконто.СубконтоДт1 = &Контрагент
		|		ИЛИ ХозрасчетныйДвиженияССубконто.СубконтоДт2 = &Контрагент)";
	Запрос.УстановитьПараметр("Счет", Счет);
	Запрос.УстановитьПараметр("Контрагент", Контрагент);

	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	Если Выборка.Следующий() Тогда
		Оборот = Выборка.Сумма;
	КонецЕсли;

	Возврат Оборот;

КонецФункции
